import{_ as a,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"72B. Special Disaster Leave","description":"","frontmatter":{"title":"72B. Special Disaster Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","personal-leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/72B-special-disaster-leave.md","filePath":"ebas/nurses-midwives/leave/72B-special-disaster-leave.md"}'),o={name:"ebas/nurses-midwives/leave/72B-special-disaster-leave.md"};function i(l,e,n,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_72b-special-disaster-leave" tabindex="-1">72B. Special Disaster Leave <a class="header-anchor" href="#_72b-special-disaster-leave" aria-label="Permalink to &quot;72B. Special Disaster Leave&quot;">​</a></h1><p><strong>(a)</strong> From 24 June 2024, special disaster leave of up to 3 days per occasion is payable where:</p><p><strong>(i)</strong> the Employee is a full-time or part-time Employee;</p><p><strong>(ii)</strong> personal leave is not available either because the Employee has exhausted the accrual or in the circumstance does not qualify for personal leave; and</p><p><strong>(iii)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(A)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(B)</strong> the lives or safety of their Immediate family or household members are threatened; or</p><p><strong>(C)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Employee&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>(b)</strong> Special disaster leave is non-cumulative.</p><p><strong>(c)</strong> Where requested by the Employer, the Employee must provide evidence that would satisfy a reasonable person of the reasons for accessing leave under this clause.</p><p>Plain language terms: disaster leave, emergency leave, flood leave, bushfire leave.</p>',11)])])}const v=a(o,[["render",i]]);export{u as __pageData,v as default};
